INSERT INTO public.rubrics_resource (created_at, active, generated, mcp, id, name, description, department_ids, total_points, pass_points, simulation_rubric, video_rubric, standard_group_ids) VALUES ('2026-03-10 17:25:10.724934+00:00', true, false, false, 'a0f0130d-75eb-524e-8961-34c0d1be8d8b', 'Communication Skills', 'Evaluates clarity of explanations, active listening techniques, and empathy demonstrated during student interactions. Assesses whether the trainee adapts language to the student''s level of understanding and confirms comprehension before moving on.', '{}', 0, 0, false, false, '{}') ON CONFLICT (id) DO NOTHING;
