INSERT INTO public.rubrics_resource (created_at, active, generated, mcp, id, name, description, department_ids, total_points, pass_points, simulation_rubric, video_rubric, standard_group_ids) VALUES ('2026-03-10 17:25:10.737611+00:00', true, false, false, '151bd5e8-cdbf-59d8-a419-3856d4a47d7c', 'De-escalation', 'Evaluates conflict resolution approach, emotional regulation, and problem-solving under pressure. Assesses whether the trainee acknowledges the student''s frustration, maintains a calm and professional tone, and guides the conversation toward a constructive resolution.', '{}', 0, 0, false, false, '{}') ON CONFLICT (id) DO NOTHING;
